#include <bits/stdc++.h>
using namespace std;
const int maxn=1e6+5;
int n,q,a[maxn];//n表示数组元素个数, q表示查询次数, a表示存储数组元素的数组
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>q;//输入数组元素个数n和查询次数q
	for(int i=1; i<=n; i++) {//循环读入n个数组元素
		cin>>a[i];
	}
	while(q--) {//处理q次查询
		int x;
		cin>>x;//读入要查询的数x
		int l=1,r=n;//初始化二分查找的左右边界
		while(l<r) {//当左边界小于右边界时，继续查找
			int mid=l+r>>1;//计算中间位置
			if(a[mid]<x) {//如果中间位置的数小于x，说明x在右半部分
				l=mid+1;
			} else {//否则，说明x在左半部分（包括mid）
				r=mid;
			}
		}
		if(a[l]!=x) {//查找结束后，检查a[l]是否等于x
			cout<<-1;//如果不等于，说明没找到，输出-1
		} else {

			cout<<l;//如果等于，说明找到了，输出其位置l
		}
		cout<<" ";//输出空格分隔答案

	}
	return 0;
}
